import React from 'react';
import { useAuth } from '../contexts/AuthContext';

export default function HomePage() {
  const { user, isAuthenticated } = useAuth();

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>🛍️ Добро пожаловать в магазин</h1>
      <p style={styles.text}>Полный стек: React + Express + JWT + RBAC</p>
      
      {isAuthenticated ? (
        <div style={styles.card}>
          <h3>Вы вошли как:</h3>
          <p><strong>Имя:</strong> {user?.first_name} {user?.last_name}</p>
          <p><strong>Email:</strong> {user?.email}</p>
          <p><strong>Роль:</strong> <span style={styles.role}>{user?.role}</span></p>
        </div>
      ) : (
        <div style={styles.card}>
          <p>👋 Для работы с товарами необходимо войти в систему</p>
          <div style={styles.buttons}>
            <a href="/login" style={styles.btn}>Вход</a>
            <a href="/register" style={styles.btn}>Регистрация</a>
          </div>
        </div>
      )}
    </div>
  );
}

const styles = {
  container: { maxWidth: '800px', margin: '0 auto', padding: '20px' },
  title: { color: '#4ade80', textAlign: 'center' },
  text: { textAlign: 'center', color: '#888' },
  card: { background: '#1a1f2e', padding: '20px', borderRadius: '12px', marginTop: '20px' },
  role: { background: '#4ade80', color: '#0b0f19', padding: '4px 8px', borderRadius: '4px' },
  buttons: { display: 'flex', gap: '10px', marginTop: '20px' },
  btn: { background: '#4ade80', color: '#0b0f19', padding: '10px 20px', borderRadius: '8px', textDecoration: 'none' }
};
